统计01状态，需要用到另类lazy标记的线段树，本质上仍然是一道板子


题意概括现有 n 盏灯排成一排，从左到右依次编号为：1，2，……，n。然后依次执行 m 项操作。
操作分为两种：

指定一个区间 [a,b]，然后改变编号在这个区间内的灯的状态（把开着的灯关上，关着的灯打开）；
指定一个区间 [a,b]，要求你输出这个区间内有多少盏灯是打开的。

灯在初始时都是关着的。
题目分析对于这样一道区间修改/区间查询的题目，我们自然而然地想到了使用分块/莫队/线段树这样的方法，而白泽在这里介绍一种线段树的解题方式。
由于每一次更新时，我们进行的操作是让关着的灯打开、开着的灯关上，因此我们可以很自然地想到，对于一个区间操作一次所得到的值，即为该区间的长度-该区间当前开着灯的数量，因为关着的灯变成了开着的，开着的灯变成了关着的。而对于lazy标记而言，因为进行两次同样的操作相当于不进行任何操作，因此我们只用使之记录0/1两个值，代表当前是否需要对此节点进行修改即可。考虑到需要将0变为1，把1变为0，为了简便起见，我们直接对lazy标记使用异或操作，每次需要修改时对其当前值异或1即可。
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define maxn 200005
using namespace std;

inline int read() &#123;
	register char c &#x3D; getchar();
	register int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;
int a[maxn], sumv[maxn &lt;&lt; 2], lazy[maxn &lt;&lt; 2];

inline void pushup(int id) &#123;
	sumv[id] &#x3D; sumv[id &lt;&lt; 1] + sumv[id &lt;&lt; 1 | 1];
&#125;

inline void pushdown(int id, int m) &#123;
	if (lazy[id]) &#123;
		lazy[id &lt;&lt; 1] ^&#x3D; 1;
		lazy[id &lt;&lt; 1 | 1] ^&#x3D; 1;
		sumv[id &lt;&lt; 1] &#x3D; (m - (m &gt;&gt; 1)) - sumv[id &lt;&lt; 1];
		sumv[id &lt;&lt; 1 | 1] &#x3D; (m &gt;&gt; 1) - sumv[id &lt;&lt; 1 | 1];
		lazy[id] &#x3D; 0;
	&#125;
&#125;

void build(int id, int l, int r) &#123;
	if (l &#x3D;&#x3D; r) &#123;
		sumv[id] &#x3D; a[l];
		return;
	&#125;
	int mid &#x3D; (l + r) &gt;&gt; 1;
	build(id &lt;&lt; 1, l, mid);
	build(id &lt;&lt; 1 | 1, mid + 1, r);
	pushup(id);
&#125;

void update(int id, int l, int r, int x, int y) &#123;
	if (x &lt;&#x3D; l &amp;&amp; r &lt;&#x3D; y) &#123;
		sumv[id] &#x3D; (r - l + 1) - sumv[id];
		lazy[id] ^&#x3D; 1;
		return;
	&#125;
	pushdown(id, r - l + 1);
	int mid &#x3D; (l + r) &gt;&gt; 1;
	if (x &lt;&#x3D; mid)
		update(id &lt;&lt; 1, l, mid, x, y);
	if (y &gt; mid)
		update(id &lt;&lt; 1 | 1, mid + 1, r, x, y);
	pushup(id);
&#125;

int query(int id, int l, int r, int x, int y) &#123;
	if (x &lt;&#x3D; l &amp;&amp; r &lt;&#x3D; y) &#123;
		return sumv[id];
	&#125;
	pushdown(id, r - l + 1);
	int mid &#x3D; (l + r) &gt;&gt; 1;
	int ans &#x3D; 0;
	if (x &lt;&#x3D; mid)
		ans +&#x3D; query(id &lt;&lt; 1, l, mid, x, y);
	if (y &gt; mid)
		ans +&#x3D; query(id &lt;&lt; 1 | 1, mid + 1, r, x, y);
	return ans;
&#125;
int n, m;

signed main() &#123;
	n &#x3D; read(), m &#x3D; read();
	for (register int i &#x3D; 1; i &lt;&#x3D; n; i++)
		a[i] &#x3D; 0;
	build(1, 1, n);
	while (m--) &#123;
		int cmd &#x3D; read();
		if (cmd &#x3D;&#x3D; 0) &#123;
			int l &#x3D; read(), r &#x3D; read();
			update(1, 1, n, l, r);
		&#125; else &#123;
			int l &#x3D; read(), r &#x3D; read();
			cout &lt;&lt; query(1, 1, n, l, r) &lt;&lt; endl;
		&#125;
		&#x2F;&#x2F;cout &lt;&lt; query(1, 1, n, 1, n) &lt;&lt; &quot;&lt;--\n&quot;;
	&#125;
	return 0;
&#125;

