题目分析很简单的线段树裸题，题目涉及区间修改/单点修改，于是我们直接套用区间修改与查询的模板，时间复杂度为$O(NlogN)$。
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define maxn 400005
using namespace std;

inline int read() &#123;
	char c &#x3D; getchar();
	int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;
int a[maxn], sumv[maxn &lt;&lt; 1], lazy[maxn &lt;&lt; 1];

inline void pushup(int id) &#123;
	sumv[id] &#x3D; sumv[id &lt;&lt; 1] + sumv[id &lt;&lt; 1 | 1];
&#125;

inline void pushdown(int id, int m) &#123;
	if (lazy[id]) &#123;
		lazy[id &lt;&lt; 1] +&#x3D; lazy[id];
		lazy[id &lt;&lt; 1 | 1] +&#x3D; lazy[id];
		sumv[id &lt;&lt; 1] +&#x3D; lazy[id] * (m - (m &gt;&gt; 1));
		sumv[id &lt;&lt; 1 | 1] +&#x3D; lazy[id] * (m &gt;&gt; 1);
		lazy[id] &#x3D; 0;
	&#125;
&#125;

inline void build(int id, int l, int r) &#123;
	if (l &#x3D;&#x3D; r) &#123;
		sumv[id] &#x3D; a[l];
		return;
	&#125;
	int mid &#x3D; (l + r) &gt;&gt; 1;
	build(id &lt;&lt; 1, l, mid);
	build(id &lt;&lt; 1 | 1, mid + 1, r);
	pushup(id);
&#125;

inline void update(int id, int l, int r, int x, int y, int v) &#123;
	if (x &lt;&#x3D; l &amp;&amp; r &lt;&#x3D; y) &#123;
		sumv[id] +&#x3D; v * (r - l + 1);
		lazy[id] +&#x3D; v;
		return;
	&#125;
	&#x2F;&#x2F;cout &lt;&lt; id &lt;&lt; &quot;&lt;--&quot; &lt;&lt; l &lt;&lt; &quot; &quot; &lt;&lt; r &lt;&lt; endl;
	pushdown(id, r - l + 1);
	int mid &#x3D; (l + r) &gt;&gt; 1;
	if (x &lt;&#x3D; mid)
		update(id &lt;&lt; 1, l, mid, x, y, v);
	if (y &gt; mid)
		update(id &lt;&lt; 1 | 1, mid + 1, r, x, y, v);
	pushup(id);
&#125;

inline int query(int id, int l, int r, int x, int y) &#123;
	if (x &lt;&#x3D; l &amp;&amp; r &lt;&#x3D; y)
		return sumv[id];
	pushdown(id, r - l + 1);
	int mid &#x3D; (l + r) &gt;&gt; 1;
	int ans &#x3D; 0;
	if (x &lt;&#x3D; mid)
		ans +&#x3D; query(id &lt;&lt; 1, l, mid, x, y);
	if (y &gt; mid)
		ans +&#x3D; query(id &lt;&lt; 1 | 1, mid + 1, r, x, y);
	return ans;
&#125;
int n, m;

signed main() &#123;
	n &#x3D; read(), m &#x3D; read();
	for (register int i &#x3D; 1; i &lt;&#x3D; n; i++)
		a[i] &#x3D; read();
	build(1, 1, n);
	while (m--) &#123;
		int cmd &#x3D; read();
		if (cmd &#x3D;&#x3D; 1) &#123;
			int l &#x3D; read(), r &#x3D; read(), k &#x3D; read();
			update(1, 1, n, l, r, k);
		&#125;
		if (cmd &#x3D;&#x3D; 2) &#123;
			int k &#x3D; read();
			update(1, 1, n, 1, 1, k);
		&#125;
		if (cmd &#x3D;&#x3D; 3) &#123;
			int k &#x3D; read();
			&#x2F;&#x2F;cout &lt;&lt; &quot;3k:&quot; &lt;&lt; k &lt;&lt; endl;
			update(1, 1, n, 1, 1, -k);
		&#125;
		if (cmd &#x3D;&#x3D; 4) &#123;
			int l &#x3D; read(), r &#x3D; read();
			cout &lt;&lt; query(1, 1, n, l, r) &lt;&lt; endl;
		&#125;
		if (cmd &#x3D;&#x3D; 5) &#123;
			cout &lt;&lt; query(1, 1, n, 1, 1) &lt;&lt; endl;
		&#125;
		&#x2F;&#x2F;cout &lt;&lt; query(1, 1, n, 1, n) &lt;&lt; &quot;&lt;---&quot; &lt;&lt; endl;
	&#125;
	return 0;
