题意概括由0和1组成的串中，不能表示为由几个相同的较小的串连接成的串，称为本原串，有多少个长为n（n&lt;=100000000)的本原串？答案mod2008。例如，100100不是本原串，因为他是由两个100组成，而1101是本原串。
题目分析简单递归。同样先分析简单情况——当其长度为1时，仅有1和2两种情况；当其长度为2时，则有10、01两种情况。向广泛情况推断，当我们目前有长度为n的一个本原串时，假设n有约数x，该串总能被划分为x份，且其不全部相同。而其划分的每一份又可以划分为更小的数，依次递归，最后可以回到长度为1、2的情况。最后，我们减去整个数列全是1、全是0的两种情况即可。
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define mod 2008
using namespace std;

int ksm(int a, int b) &#123;
	int res &#x3D; 1;
	while (b) &#123;
		if (b &amp; 1) &#123;
			res *&#x3D; a;
			res %&#x3D; mod;
		&#125;
		b &gt;&gt;&#x3D; 1;
		a *&#x3D; a;
		a %&#x3D; mod;
	&#125;
	return res;
&#125;

int dfs(int now) &#123;
	if (now &#x3D;&#x3D; 1)
		return 2;
	int sum &#x3D; 0;
	for (int i &#x3D; 2; i * i &lt;&#x3D; now; i++) &#123;
		if (now % i &#x3D;&#x3D; 0) &#123;
			sum &#x3D; (sum + dfs(i)) % mod;
			if (now &#x2F; i !&#x3D; i) &#123;
				sum &#x3D; (sum + dfs(now &#x2F; i)) % mod;
			&#125;
		&#125;
	&#125;
