题意概括有初始值a=0，进行x次操作，共有如下三种操作模式：

add：使a增加1
for num：将其和与之适配的end之间所有操作循环执行num次
end：与for适配

如果a的值大于$2^{32}$，输出**OVERFLOW!!!**，否则输出a。
题目分析没啥好说的模拟-.-
坑点：for循环经过多次堆叠后每次add操作的值有可能大于longlong范围，当然也有可能多次堆叠后不进行add操作，使得堆叠的值又慢慢变小，因此我们可以利用栈存储堆叠到当前状态下需要循环的总次数，而非单次循环的次数。
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
using namespace std;
int n, now;
stack&lt;int&gt; st;

signed main() &#123;
	ios::sync_with_stdio(false);
	int loop &#x3D; pow(2, 32);
	cin &gt;&gt; n;
	st.push(1);
	while (n--) &#123;
		string command;
		cin &gt;&gt; command;
		if (command &#x3D;&#x3D; &quot;add&quot;) &#123;
			now +&#x3D; st.top();
			if (now &gt;&#x3D; loop) &#123;
				puts(&quot;OVERFLOW!!!&quot;);
				return 0;
			&#125;
		&#125; else if (command &#x3D;&#x3D; &quot;for&quot;) &#123;
			int temp;
			cin &gt;&gt; temp;
			if (temp &#x3D;&#x3D; 0)
				continue;
			st.push(min(st.top()*temp, loop));
		&#125; else &#123;
			if (st.empty())
				continue;
			int temp &#x3D; st.top();
			st.pop();
		&#125;
	&#125;
	cout &lt;&lt; now &lt;&lt; endl;
	return 0;
&#125;

