题意概括小渊和小轩是好朋友也是同班同学，他们在一起总有谈不完的话题。一次素质拓展活动中，班上同学安排做成一个 m 行 n 列的矩阵，而小渊和小轩被安排在矩阵对角线的两端，因此，他们就无法直接交谈了。幸运的是，他们可以通过传纸条来进行交流。纸条要经由许多同学传到对方手里，小渊坐在矩阵的左上角，坐标 (1,1)，小轩坐在矩阵的右下角，坐标 (m,n)。从小渊传到小轩的纸条只可以向下或者向右传递，从小轩传给小渊的纸条只可以向上或者向左传递。
在活动进行中，小渊希望给小轩传递一张纸条，同时希望小轩给他回复。班里每个同学都可以帮他们传递，但只会帮他们一次，也就是说如果此人在小渊递给小轩纸条的时候帮忙，那么在小轩递给小渊的时候就不会再帮忙。反之亦然。
还有一件事情需要注意，全班每个同学愿意帮忙的好感度有高有低（注意：小渊和小轩的好心程度没有定义，输入时用 0 表示），可以用一个 [0,100] 内的自然数来表示，数越大表示越好心。小渊和小轩希望尽可能找好心程度高的同学来帮忙传纸条，即找到来回两条传递路径，使得这两条路径上同学的好心程度之和最大。现在，请你帮助小渊和小轩找到这样的两条路径。
题目分析类似于P1004方格取数问题，考虑一条路的情况，很轻易地可以得到到达每一个点的转移方程：
$$dp_{i,j}=max(dp_{i-1,j},dp_{i,j-1})+a_{i,j}$$其中dp为转移数组，a记录方格图上的数。
此时再考虑需要走两条路的情况。由于进行第一次动态规划时难以记录走过的路径，因此我们选择一次记录四个状态，即第一条路的当前位置与第二条路的当前位置。因为走两条路时，每条路径上任意一点的最大值仍然独立地遵循一条路时的规则，故我们可以得到这样一个新的转移方程：$$dp_{i,j,k,l}=max(dp_{i-1,j,k-1,l},dp_{i-1,j,k,l-1},dp_{i,j-1,k-1,l},dp_{i,j-1,k,l-1})+a_{i,j}+a_{k,l}$$当然，由于两条路不能走过同样的点，因此当(i,j)与(k,l)为同一点时，我们令结果不能被取到：$$if(i=k\ and\ j=l)dp_{i,j,k,l}=-1$$
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define maxn 55
using namespace std;

inline int read() &#123;
	register char c &#x3D; getchar();
	register int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;
int n, m;
int a[maxn][maxn];
int dp[maxn][maxn][maxn][maxn];

bool startOrFinish(int x1, int y1, int x2, int y2) &#123;
	if (x1 &#x3D;&#x3D; 1 &amp;&amp; y1 &#x3D;&#x3D; 1 &amp;&amp; x2 &#x3D;&#x3D; 1 &amp;&amp; y2 &#x3D;&#x3D; 1)
		return true;
	if (x1 &#x3D;&#x3D; n &amp;&amp; y1 &#x3D;&#x3D; m &amp;&amp; x2 &#x3D;&#x3D; n &amp;&amp; y2 &#x3D;&#x3D; m)
		return true;
	return false;
&#125;

signed main() &#123;
	n &#x3D; read(), m &#x3D; read();
	for (register int i &#x3D; 1; i &lt;&#x3D; n; i++) &#123;
		for (register int j &#x3D; 1; j &lt;&#x3D; m; j++)
			a[i][j] &#x3D; read();
	&#125;
	for (register int i &#x3D; 1; i &lt;&#x3D; n; i++) &#123;
		for (register int j &#x3D; 1; j &lt;&#x3D; m; j++) &#123;
			for (register int k &#x3D; 1; k &lt;&#x3D; n; k++) &#123;
				for (register int l &#x3D; 1; l &lt;&#x3D; m; l++) &#123;
					if (i &#x3D;&#x3D; k &amp;&amp; j &#x3D;&#x3D; l &amp;&amp; !startOrFinish(i, j, k, l))
						dp[i][j][k][l] &#x3D; -1;
					else
						dp[i][j][k][l] &#x3D; max(max(dp[i - 1][j][k - 1][l], dp[i - 1][j][k][l - 1]), max(dp[i][j - 1][k - 1][l],
						                     dp[i][j - 1][k][l - 1])) + a[i][j] + a[k][l];
					&#x2F;&#x2F;cout &lt;&lt; i &lt;&lt; &quot; &quot; &lt;&lt; j &lt;&lt; &quot; &quot; &lt;&lt; k &lt;&lt; &quot; &quot; &lt;&lt; l &lt;&lt; &quot; &quot; &lt;&lt; dp[i][j][k][l] &lt;&lt; endl;
				&#125;
			&#125;
		&#125;
	&#125;
	cout &lt;&lt; dp[n][m][n][m];
	return 0;
&#125;

