题意概括蒜头君手上有一些小木棍，它们长短不一，蒜头君想用这些木棍拼出一个等边三角形，并且每根木棍都要用到。 例如，蒜头君手上有长度为 1，2，3，3的4根木棍，他可以让长度为1，2的木棍组成一条边，另外2跟分别组成2条边，拼成一个边长为3的等边三角形。蒜头君希望你提前告诉他能不能拼出来，免得白费功夫。
题目分析同样是简单搜索，不过要运用到一些剪枝的策略。搜索时只需要将所有木棒分为三堆，枚举地将每根木棒都放入其中一堆，直到试完所有情况或完成题目要求即可。剪枝方面，我们先将所有木棒的总长度与3相除，若不能整除则说明木棒永远不可能拼接为等边三角形。其次，我们取总长度的三分之一，若某一堆木棒的当前长度已经超过了该值，同样也不可能拼接出等边三角形。
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define maxn 30
using namespace std;

int read() &#123;
	char c &#x3D; getchar();
	int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;
int n, ans;
int lengthSum;
int a[maxn];
bool isUsed[maxn];

bool dfs(int need, int f1, int f2, int f3) &#123;
	if (f1 &#x3D;&#x3D; f2 &amp;&amp; f2 &#x3D;&#x3D; f3 &amp;&amp; need &#x3D;&#x3D; 0) &#123;
		return 1;
	&#125; else if (need &lt;&#x3D; 0)
		return 0;
	if (f1 &gt; lengthSum || f2 &gt; lengthSum || f3 &gt; lengthSum)
		return 0;
	&#x2F;&#x2F;cout &lt;&lt; need &lt;&lt; &quot; &quot; &lt;&lt; f1 &lt;&lt; &quot; &quot; &lt;&lt; f2 &lt;&lt; &quot; &quot; &lt;&lt; f3 &lt;&lt; endl;
	for (register int i &#x3D; 0; i &lt; n; i++) &#123;
		if (!isUsed[i]) &#123;
			isUsed[i] &#x3D; 1;
			if (dfs(need - 1, f1 + a[i], f2, f3) || dfs(need - 1, f1, f2 + a[i], f3) || dfs(need - 1, f1, f2, f3 + a[i]))
				return 1;
			isUsed[i] &#x3D; 0;
			return 0;
		&#125;
	&#125;
	return 0;
&#125;

signed main() &#123;
	n &#x3D; read();
	for (register int i &#x3D; 0; i &lt; n; i++)
		a[i] &#x3D; read(), lengthSum +&#x3D; a[i];
	if (lengthSum % 3 !&#x3D; 0) &#123;
		cout &lt;&lt; &quot;no&quot; &lt;&lt; endl;
		return 0;
	&#125;
	lengthSum &#x2F;&#x3D; 3;
	if (dfs(n, 0, 0, 0))
		cout &lt;&lt; &quot;yes&quot;;
	else
		cout &lt;&lt; &quot;no&quot;;
	return 0;
