奇怪的题面QAQ


题意概括马上就要放寒假了，蒜头君已经辛勤的工作一年了，打算和家人一起出去旅游放松放松。有经验的人一定知道，出去旅游前一定要有详细的旅行规划。蒜头君打算旅游 n 个城市，但并不是每条路线的花费都是一样的。蒜头君是一个勤俭节俭的人，他就在想怎么把所有的城市旅游一遍花费最小呢？（蒜头君不喜欢重复旅游同一个城市，也就是说已到达过的城市蒜头君是不会再次光临的）求从1号城市出发，经过所有景点且不重复，最后回到起点的最小花费。
题目分析题面写得很迷啊…说是先旅行经过每个城市，然后再返回起点——事实上回来的时候不用找回起点的最短路，而是最终到达哪个城市就直接从那个城市返回起点就行了。
所以依旧是老做法，从起点开始搜，找到一个终点，使得所有点都被访问过且从起点经过其他点到达终点、再从终点直接返回起点的距离和最小即可。注意剪枝。/
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define maxn 20
using namespace std;

int read() &#123;
	char c &#x3D; getchar();
	int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;
int n;
int a[maxn][maxn];
int flag[maxn];
int ans &#x3D; 0x3f3f3f3f;

void dfs(int now, int dis, int need) &#123;
	&#x2F;&#x2F;cout &lt;&lt; now &lt;&lt; &quot; &quot; &lt;&lt; dis &lt;&lt; &quot; &quot; &lt;&lt; need &lt;&lt; endl;
	if (dis &gt; ans)
		return;
	if (need &#x3D;&#x3D; 0) &#123;
		ans &#x3D; min(ans, dis + a[now][0]);
		return;
	&#125;
	flag[now] &#x3D; 1;
	for (register int i &#x3D; 0; i &lt; n; i++) &#123;
		if (flag[i])
			continue;
		dfs(i, dis + a[now][i], need - 1);
	&#125;
	flag[now] &#x3D; 0;
	return;
&#125;

signed main() &#123;
	n &#x3D; read();
	for (register int i &#x3D; 0; i &lt; n; i++) &#123;
		for (register int j &#x3D; 0; j &lt; n; j++) &#123;
			a[i][j] &#x3D; read();
		&#125;
	&#125;
	dfs(0, 0, n - 1);
	cout &lt;&lt; ans  &lt;&lt; endl;
	return 0;
