题意概括蒜头君在求解一个 n 元的高次方程：$$k_1x_1^{p_1}+k_2x_2^{p_2}+…+k_nx_n^{p_n}=0$$其中：$x_1,x_2,\ldots,x_n$ 是未知数，$k_1,k_2,\ldots,k_n $是系数，$p_1,p_2,\ldots,p_n 是$指数。方程中所有数都一定是整数。
假设未知数 $1\leq x_i\leq M,i=1 \ldots n$​。你能帮蒜头君算出这个方程的整数解个数吗？
题目分析同样是搜索，枚举每个数字可能的值，直到达到数的上界为止。
当然也可以写成for循环嵌套的形式=W=。
这种题不知道题解要写些什么…思路这些都是顺着就来了…
所以就这样了！
代码#include &lt;bits&#x2F;stdc++.h&gt;
#define int long long
#define maxn 10
using namespace std;

int read() &#123;
	char c &#x3D; getchar();
	int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;

int ksm(int a, int n) &#123;
	int res &#x3D; 1;
	while (n) &#123;
		if (n &amp; 1) &#123;
			res &#x3D; res * a;
		&#125;
		n &gt;&gt;&#x3D; 1;
		a &#x3D; a * a;
	&#125;
	return res;
&#125;
int n, M;
int k[maxn], p[maxn], X[maxn];
int maxNum[maxn];
int ans;

void dfs(int x) &#123;
	int temp &#x3D; 0;
	for (register int i &#x3D; 0; i &lt; n; i++) &#123;
		temp +&#x3D; k[i] * ksm(X[i], p[i]);
		if (X[i] &gt; M)
			return;
	&#125;
	&#x2F;&#x2F;cout &lt;&lt; X[0] &lt;&lt; &quot; &quot; &lt;&lt; X[1] &lt;&lt; &quot; &quot; &lt;&lt; X[2] &lt;&lt; &quot; &quot; &lt;&lt; endl;
	if (temp &#x3D;&#x3D; 0) &#123;
		ans++;
	&#125;
	for (register int i &#x3D; x; i &lt; n; i++) &#123;
		X[i]++;
		dfs(i);
		X[i]--;
	&#125;
&#125;

signed main(void) &#123;
	n &#x3D; read();
	M &#x3D; read();
	for (register int i &#x3D; 0; i &lt; n; i++)
		k[i] &#x3D; read(), p[i] &#x3D; read(), X[i] &#x3D; 1;
	dfs(0);
	cout &lt;&lt; ans &lt;&lt; endl;
	return 0;
&#125;

