题意概括2020 年，蒜头君自己开了一家拥有 N 个员工的大公司。每天，蒜头君都要分配 N 项工作给他的员工，但是，由于能力的不同，每个人对处理相同工作所需要的时间有所差异。
众所周知，蒜头君是一个非常重视效率的人，他想知道该如何分配工作，才能使得完成所有工作的时间总和最小（每个员工只可以被分配到一个工作）。
题目分析抽象搜索，我们假设开始时第i个人做第i份工，因为每个人只能做一份工，因此我们使每个人依次与其他人交换工作，并以该新状态进行下一层搜索，即可得到最终答案。
关于可行性这一块儿，试想：每个人只做一份工，做工总数与人数相等，无论所有人做工顺序是什么，总能通过两两交换的形式变为编号为i的人做第i份工的状态，因此原思路可以遍历所有状态，即具有可行性与正确性。
代码#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;

int read() &#123;
	char c &#x3D; getchar();
	int f &#x3D; 1, _ &#x3D; 0;
	while (c &gt; &#39;9&#39; || c &lt; &#39;0&#39;)
		f &#x3D; (c &#x3D;&#x3D; &#39;-&#39;) ? -1 : 1, c &#x3D; getchar();
	while (c &lt;&#x3D; &#39;9&#39; &amp;&amp; c &gt;&#x3D; &#39;0&#39;)
		_ &#x3D; (_ &lt;&lt; 3) + (_ &lt;&lt; 1) + (c ^ 48), c &#x3D; getchar();
	return _ * f;
&#125;
int n;
int workTime[20][20];
int workNote[20];
int ans &#x3D; 0x3f3f3f3f;;

void dfs(int now) &#123;
	if (now &#x3D;&#x3D; n) &#123;
		int sum &#x3D; 0;
		for (register int i &#x3D; 0; i &lt; n; i++)
			sum +&#x3D; workTime[i][workNote[i]];
		ans &#x3D; min(ans, sum);
	&#125; else &#123;
		for (register int i &#x3D; now; i &lt; n; i++) &#123;
			swap(workNote[i], workNote[now]);
			dfs(now + 1);
			swap(workNote[i], workNote[now]);
		&#125;
	&#125;
&#125;

int main() &#123;
	n &#x3D; read();
	for (register int i &#x3D; 0; i &lt; n; i++) &#123;
		for (register int j &#x3D; 0; j &lt; n; j++)
			workNote[i] &#x3D; i, workTime[i][j] &#x3D; read();
	&#125;
	dfs(0);
	cout &lt;&lt; ans &lt;&lt; endl;
